const input = $json;
const payload = input.body ?? input;
const body = typeof payload === 'string' ? JSON.parse(payload) : payload;
const template = String(body.queryTemplate ?? '').trim();
if (!template) {
  throw new Error('queryTemplate is required');
}
const requestedCount = Number(body.count ?? 5);
const count = Number.isFinite(requestedCount) && requestedCount > 0
  ? Math.min(Math.trunc(requestedCount), 20)
  : 5;
const executeAtUtc = body.executeAtUtc ?? null;
const timezone = body.timezone ?? 'UTC';
const query = template;
const queryParts = [];
const appendQuery = (name, value, transform = (text) => text) => {
  const text = String(value ?? '').trim();
  if (!text || ['null', 'undefined'].includes(text.toLowerCase())) {
    return;
  }
  queryParts.push(`${name}=${encodeURIComponent(transform(text))}`);
};
appendQuery('q', query);
appendQuery('count', count);
appendQuery('country', body.country, (text) => text.toUpperCase());
appendQuery('search_lang', body.searchLang, (text) => text.toLowerCase());
appendQuery('freshness', body.freshness);
const braveSearchUrl = `https://api.search.brave.com/res/v1/web/search?${queryParts.join('&')}`;
return [{ json: { ...body, query, count, timezone, executeAtUtc, braveSearchUrl } }];

const response = $json;
const request = $('Prepare Web Search').first().json;
const results = (response.web?.results ?? []).slice(0, Number(request.count ?? 5)).map((item) => ({
  title: item.title ?? null,
  url: item.url ?? item.profile?.url ?? null,
  description: item.description ?? item.snippet ?? null,
  source: item.meta_url?.hostname ?? item.profile?.name ?? null
}));
const llmContext = results
  .map((item, index) => `${index + 1}. ${item.title ?? 'Untitled'}\n${item.url ?? ''}\n${item.description ?? ''}`.trim())
  .join('\n\n');
return [{ json: {
  query: request.query,
  retrievedAtUtc: new Date().toISOString(),
  results,
  llmContext
} }];
